#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long a, b, n;
        scanf("%lld %lld %lld", &a, &b, &n);
        long long len = (long long)ceil(log2(n));
        long long sum = (len * n * b) + ((n - (1LL << (len - 1))) * a);
        printf("%lld\n", sum);
    }
    return 0;
}

